query:
_sourceCategory={{sourcecategory}} _collector={{collector}} 
{{keywords}}
| limit {{limit}}
| tostring(_messageid) as messageid
| {{plus_minus_seconds}} as buffer_seconds
| _messagetime + (buffer_seconds * 1000) as end
| _messagetime - (buffer_seconds * 1000) as start
| "https://live.us2.sumologic.com/ui/#/search/@" as endpoint

// prepare the category strings
| concat("_sourcecategory=",_sourcecategory) as sc
| concat("_sourcename=",_sourcename) as sn
| concat("_collector=",_collector) as c

// suppress scientific notation must be epoch
| format( "%.0f",end) as end
| format( "%.0f",start) as start

// fix if they put a space in their stuff
| replace(sc," ","?") as sc
| replace(sn," ","?") as sn
| replace(c," ","?") as c

// create one meta to avoid the 10 param limit on concat.
| concat (sc," ",sn," ",c) as meta

// add an invaid not condition and the keywords so we get highlighting in the UI
//  ((not XXIGNOREDXX) or 7c08249862244770a65050bbb14c1e70)
| concat ("%0A",urlencode("((not XXIGNOREDXX) or {{keywords}})")) as searched

// build a custom query that will show n messages each side of the event within the time range using it's message id
//  | "1013436549599799094" as mid |  abs(_messageid - mid) as offset | sort offset asc | limit 25 | tostring(_messageid) as id | fields -mid,offset | sort _messagetime
| concat( " | \"",messageid,"\" as mid | abs(_messageid - mid) as offset | sort offset asc | limit ",round({{max_events}})," | tostring(_messageid) as id | fields -mid,offset,id | sort _messagetime")  as suffix

| replace(_sourcename," ","?") as show_source_string
| tourl(concat(endpoint,start,",",end,"@",urlencode(meta),searched,"%0A",urlencode(suffix)),show_source_string) as  %"Show Source" 
| fields -sc ,sn,c,endpoint,buffer_seconds
| _messagetime as time
| count by time,_sourcecategory,_collector,%"Show Source",_raw | fields -_count
| formatdate(time,"yyy-MM-dd HH:mm:ss.SSS ZZZZ") as time
